// Log observability metrics
const startTime = $('Workflow Configuration').item.json.timestamp || new Date().toISOString();
const currentTime = new Date().toISOString();

// Calculate response time in milliseconds
const responseTime = new Date(currentTime) - new Date(startTime);

// Determine escalation status based on which path was taken
const escalationStatus = $input.item.json.escalated || false;

// Get intelligence data from Support Intelligence Agent
const intelligenceData = $('Support Intelligence Agent').item.json;

const metrics = {
  response_time: responseTime,
  escalation_status: escalationStatus,
  model_used: 'anthropic',
  category: intelligenceData.category || 'unknown',
  urgency: intelligenceData.urgency || 'unknown',
  sentiment: intelligenceData.sentiment || 'unknown',
  churn_risk: intelligenceData.churn_risk || 'unknown',
  timestamp: currentTime
};

// Get observability endpoint from Workflow Configuration
const observabilityEndpoint = $('Workflow Configuration').item.json.observability_endpoint;

if (observabilityEndpoint) {
  try {
    // Send metrics to observability endpoint
    await $http.post(observabilityEndpoint, {
      body: metrics,
      headers: {
        'Content-Type': 'application/json'
      }
    });

    return {
      json: {
        success: true,
        metrics: metrics,
        message: 'Metrics logged successfully'
      }
    };
  } catch (error) {
    return {
      json: {
        success: false,
        metrics: metrics,
        error: error.message,
        message: 'Failed to send metrics to observability endpoint'
      }
    };
  }
} else {
  // If no endpoint configured, just return the metrics
  return {
    json: {
      success: true,
      metrics: metrics,
      message: 'No observability endpoint configured, metrics collected only'
    }
  };
}
